Here's a C++ program that reads a text file line by line and counts the occurrences of a specific word:

```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
#include <map>

using namespace std;

int countWordOccurences(const string& filename, const string& word) {
    int count = 0;
    map<string, int> wordCount;

    ifstream file(filename);
    if (file.is_open()) {
        string line, temp;
        while (getline(file, line)) {
            istringstream iss(line);
            while (iss >> temp) {
                string.lowercase(temp); // Convert to lowercase for case-insensitive comparison
                if (temp == word) {
                    ++count;
                }
                wordCount[temp] = (wordCount.count(temp)) ? wordCount[temp] + 1 : 1;
            }
        }
        file.close();
    } else {
        cout << " Unable to open file";
        return -1; // Return error code
    }

    // Print the word count
    cout << "Word '" << word << "': " << count << " occurrences\n";
    cout << "Total unique words: " << wordCount.size() << endl;

    return 0;
}

int main() {
    string filename = "input.txt"; // Replace with your file name
    string word = "hello"; // Replace with the word to count

    countWordOccurences(filename, word);
    return 0;
}
```

In this program:

1. We define a function `countWordOccurences` that takes a file name and a word as input.
2. We use an `ifstream` object to read the file line by line.
3. For each line, we split it into individual words using an `istringstream`.
4. We convert each word to lowercase using the `tolower` function for case-insensitive comparison.
5. We increment a counter `count` for each occurrence of the specified word and update a `map` `wordCount` to store the unique words and their counts.
6. Finally, we print the total count and the number of unique words.

**Note:**

* Make sure to replace `input.txt` and `hello` with your actual file name and the word you want to count, respectively.
* This program assumes the word separator is a space character. If you need to handle other separators (e.g., tabs, commas), modify the `istringstream` construction accordingly.
* This implementation is case-insensitive, thanks to the `tolower` conversion.

